// Aggregate GitHub activity data
const commits = $input.all()[0].json;
const prs = $input.all()[1].json;
const issues = $input.all()[2].json;
const releases = $input.all()[3].json;

// Calculate date range (last 7 days)
const now = new Date();
const oneWeekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

// Filter by date range
const recentCommits = commits.filter(c => new Date(c.commit.committer.date) >= oneWeekAgo);
const recentPRs = prs.filter(pr => new Date(pr.created_at) >= oneWeekAgo || new Date(pr.updated_at) >= oneWeekAgo);
const recentIssues = issues.filter(issue => new Date(issue.created_at) >= oneWeekAgo || new Date(issue.updated_at) >= oneWeekAgo);
const recentReleases = releases.filter(r => new Date(r.created_at) >= oneWeekAgo);

// Calculate statistics
const stats = {
  commits: {
    count: recentCommits.length,
    authors: [...new Set(recentCommits.map(c => c.commit.author.name))],
    additions: recentCommits.reduce((sum, c) => sum + (c.stats?.additions || 0), 0),
    deletions: recentCommits.reduce((sum, c) => sum + (c.stats?.deletions || 0), 0)
  },
  pullRequests: {
    opened: recentPRs.filter(pr => new Date(pr.created_at) >= oneWeekAgo && pr.state === 'open').length,
    merged: recentPRs.filter(pr => pr.merged_at && new Date(pr.merged_at) >= oneWeekAgo).length,
    closed: recentPRs.filter(pr => pr.closed_at && new Date(pr.closed_at) >= oneWeekAgo && !pr.merged_at).length,
    contributors: [...new Set(recentPRs.map(pr => pr.user.login))]
  },
  issues: {
    opened: recentIssues.filter(i => new Date(i.created_at) >= oneWeekAgo).length,
    closed: recentIssues.filter(i => i.closed_at && new Date(i.closed_at) >= oneWeekAgo).length,
    labels: [...new Set(recentIssues.flatMap(i => i.labels.map(l => l.name)))]
  },
  releases: {
    count: recentReleases.length,
    latest: recentReleases[0]?.tag_name || null
  }
};

return [{
  json: {
    repository: $input.all()[0].json[0]?.repository?.full_name || 'unknown',
    weekRange: {
      start: oneWeekAgo.toISOString(),
      end: now.toISOString()
    },
    stats: stats,
    rawData: {
      commits: recentCommits.slice(0, 10),
      pullRequests: recentPRs.slice(0, 10),
      issues: recentIssues.slice(0, 10),
      releases: recentReleases
    }
  }
}];

