// Format final summary
const aiSummary = $input.first().json.choices[0].message.content;
const data = $input.all()[1].json;

const markdownSummary = `# Weekly GitHub Activity Summary

## 📊 ${data.repository}

**Week:** ${new Date(data.weekRange.start).toLocaleDateString()} - ${new Date(data.weekRange.end).toLocaleDateString()}

---

${aiSummary}

---

## 📈 Quick Stats

| Metric | Count |
|--------|-------|
| Commits | ${data.stats.commits.count} |
| Contributors | ${data.stats.commits.authors.length} |
| Lines Added | +${data.stats.commits.additions} |
| Lines Removed | -${data.stats.commits.deletions} |
| PRs Opened | ${data.stats.pullRequests.opened} |
| PRs Merged | ${data.stats.pullRequests.merged} |
| Issues Opened | ${data.stats.issues.opened} |
| Issues Closed | ${data.stats.issues.closed} |
| Releases | ${data.stats.releases.count} |

---

*Generated by n8n GitHub Activity Workflow*
`;

return [{
  json: {
    summary: markdownSummary,
    repository: data.repository,
    stats: data.stats,
    timestamp: new Date().toISOString()
  }
}];
